#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/stat.h>
#include <dirent.h>

void init_repo() {
    mkdir(".minigit", 0755);
}

void add_file(const char *filename) {
    char hash[41];
    FILE *f = fopen(filename, "r");
    if (!f) {
        perror("fopen");
        exit(1);
    }
    // Simulate SHA1: just read first 40 bytes
    fread(hash, 1, 40, f);
    hash[40] = '\0';
    fclose(f);

    char path[256];
    snprintf(path, sizeof(path), ".minigit/%s", filename);
    FILE *out = fopen(path, "w");
    if (!out) {
        perror("fopen write");
        exit(1);
    }
    fprintf(out, "%s", hash);
    fclose(out);
}

void checkout_file(const char *filename) {
    char path[256];
    snprintf(path, sizeof(path), ".minigit/%s", filename);
    FILE *in = fopen(path, "r");
    if (!in) {
        // File not tracked, nothing to do
        return;
    }
    char content[41];
    fscanf(in, "%40s", content);
    fclose(in);

    FILE *out = fopen(filename, "w");
    if (!out) {
        perror("fopen write");
        exit(1);
    }
    fprintf(out, "%s", content);
    fclose(out);
}

void reset_file(const char *filename) {
    unlink(filename);
}

int main(int argc, char **argv) {
    if (argc < 2) {
        fprintf(stderr, "Usage: minigit <command> [file]\n");
        return 1;
    }

    if (strcmp(argv[1], "init") == 0) {
        init_repo();
    } else if (strcmp(argv[1], "add") == 0 && argc == 3) {
        add_file(argv[2]);
    } else if (strcmp(argv[1], "checkout") == 0 && argc == 3) {
        checkout_file(argv[2]);
    } else if (strcmp(argv[1], "reset") == 0 && argc == 3) {
        reset_file(argv[2]);
    } else {
        fprintf(stderr, "Unknown command\n");
        return 1;
    }

    return 0;
}
